/**
 * 战利品解析：从本条 AI 消息中解析「获得: [物品名] × 数量」或多种变体，
 * 按《物品类型获得归属》分类后追加到 stat_data.inventory；同名则累加数量。
 * 额外支持将装备类掉落写入 inventory.equipment，供状态栏“装备”页直接展示。
 */
import _ from 'lodash';

console.info('[战利品解析] 脚本已加载');

/** 「获得: [物品名] × 数量」及变体（支持中英文冒号、×/x/X、括号可选） */
const LOOT_REG =
  /获得\s*[：:]?\s*(?:\[([^\]]+)\]|【([^】]+)】|([^\s[\]【】×xX\d]+?))\s*[×xX]\s*(\d+)/g;

/** 「掉落结算」格式：物品名: 数量 或 物品名: 数量 (说明)，每行一条 */
const SETTLEMENT_REG = /^([^：:\n]+?)\s*[：:]\s*(\d+)(?:\s*\([^)]*\))?/gm;

/** 分类前缀格式：材料/消耗品/装备/重要物品：物品名 x数量 */
const CATEGORY_PREFIX_REG =
  /(?:^|\n)\s*(装备|消耗品|补给|材料|重要物品|重要道具)\s*[：:]\s*([^\n×xX\d]{2,40}?)\s*[×xX]\s*(\d+)/gm;

/** 宽松格式：行内「物品名 ×数量」或「物品名 x数量」「物品名 数量个/份/发」等；数量后可为逗号/顿号（如 lootHint 的「甲壳x2，废金属x3」） */
const LOOSE_LOOT_REG =
  /(?:^|[\s、，,，])([^\s×xX\d]{2,24}?)\s*[×xX]?\s*(\d+)\s*(?:[个份发枚、，,]|$)/gm;

/** <LootLog> 内「物品: 名称 x 数量, 名称 x 数量」整行（strip 标签后为 "物品: 变异沙蟹甲壳 x 2, 劣质废金属 x 1"） */
const LOOTLOG_ITEMS_LINE_REG = /物品\s*[：:]\s*([^\n]+)/g;
/** 上句捕获的列表里单条：名称 x 数量 或 名称 × 数量 */
const LOOTLOG_ITEM_PART_REG = /([^,×xX]+?)\s*[×xX]\s*(\d+)/g;

type LootCategory = '装备' | '消耗品' | '材料' | '重要道具';

type InventoryEquipmentEntry = {
  id: string;
  name: string;
  slot: string;
  grade: string;
  summary: string;
  flavor: string;
  maxHp: number;
  atk: number;
  def: number;
  speed: number;
  crit: number;
  effects: Array<{ name: string; description: string }>;
  quantity: number;
};

type InventorySupplyEntry = {
  id: string;
  name: string;
  category: string;
  quantity: number;
};

const EQUIPMENT_SLOT_PATTERNS: Array<{ pattern: RegExp; slot: string }> = [
  { pattern: /手枪|步枪|霰弹枪|冲锋枪|狙击枪|弓|弩|长枪|猎枪|火炮|枪械|主武器|武器/i, slot: '主武器' },
  { pattern: /短刀|匕首|军刀|砍刀|长刀|斧|锤|棍|矛|副武器/i, slot: '副武器' },
  { pattern: /头盔|头巾|兜帽|面罩|护目镜|头部/i, slot: '头部' },
  { pattern: /护甲|胸甲|外套|上衣|披风|大衣|躯干|胸部/i, slot: '躯干' },
  { pattern: /手套|护腕|臂甲|手部/i, slot: '手部' },
  { pattern: /工装裤|护腿|长裤|裤|腿甲|腿部/i, slot: '腿部' },
  { pattern: /靴|鞋|足具|足部/i, slot: '足部' },
  { pattern: /指南针|戒指|项链|吊坠|护符|徽章|饰品/i, slot: '饰品1' },
];

const EQUIPMENT_GRADE_PATTERNS: Array<{ pattern: RegExp; grade: string }> = [
  { pattern: /传说/i, grade: '传说' },
  { pattern: /史诗/i, grade: '史诗' },
  { pattern: /稀有/i, grade: '稀有' },
  { pattern: /精品|精制|精良/i, grade: '精制' },
  { pattern: /普通/i, grade: '普通' },
];

const HANDLED_MESSAGE_IDS = new Set<number>();

/** 去掉 HTML 标签和常见 markdown 粗体，避免「获得 **甲壳** x2」等解析不到 */
function stripHtmlAndMarkdown(text: string): string {
  return text
    .replace(/<[^>]+>/g, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/__([^_]+)__/g, '$1')
    .replace(/\r/g, '\n');
}

function normalizeLootText(text: string): string {
  return stripHtmlAndMarkdown(text)
    .replace(/^\s*(?:本次)?(?:战利品|掉落|获得)[：:]\s*/gm, '')
    .replace(/\r/g, '')
    .trim();
}

/** 按物品类型归属：装备 / 消耗品 / 材料 / 重要道具 */
function classifyItemType(name: string): LootCategory {
  const n = name.trim();
  if (!n) return '材料';

  // 装备：优先识别武器、防具、饰品等可穿戴/可装备物
  if (
    /手枪|步枪|霰弹枪|冲锋枪|狙击枪|弓|弩|猎枪|武器|短刀|匕首|军刀|砍刀|长刀|斧|锤|长枪|头盔|头巾|面罩|护甲|胸甲|披风|外套|手套|护腕|工装裤|护腿|裤|靴|鞋|戒指|项链|吊坠|护符|徽章|指南针|饰品/i.test(
      n,
    )
  ) {
    return '装备';
  }

  // 消耗品：弹药、医疗、食物/肉、饮用、投掷等（含蟹肉、可烹饪等）
  if (
    /子弹|弹药|弹匣|霰弹|箭矢|医疗|绷带|药品|消毒|止血|治疗|口粮|肉块|生肉|熟肉|蟹肉|可烹饪|净水|饮用水|干粮|罐头|蛋白块|手雷|烟雾弹|闪光|燃烧瓶|投掷物|电池/i.test(
      n,
    )
  )
    return '消耗品';

  // 重要道具：任务/剧情关键
  if (
    /任务物品|关键道具|信物|钥匙|情报|委托物|芯片|密信|证物|纪念物/i.test(n)
  )
    return '重要道具';

  // 材料：其余一律归材料（甲壳、废料、零件、兽皮、金属等）
  return '材料';
}

/** 掉落结算里出现的货币/非物品行不写入背包 */
function isSettlementCurrencyOrSkip(name: string): boolean {
  const n = name.trim();
  return /复兴币|金穗|^[\d\s]+g$|\(g\)/i.test(n) || n.length < 2;
}

/** 明确非物品的名称：剧情/表格/日期等，一律不写入背包 */
function isBlocklistedLootName(name: string): boolean {
  const n = name.trim();
  if (n.length < 2) return true;
  // 日期格式：2085-06-15、2024-05-20、-07 等
  if (/^\d{4}-\d{2}-\d{2}/.test(n) || /^-\d{2}$/.test(n)) return true;
  if (/\d{4}-\d{2}-\d{2}\s*-?\d*/.test(n) && n.length <= 24) return true;
  // 剧情/总结/表格/选项类
  if (/剧情大纲|总体大纲|随机物品生成池|选项表|总结表|地图元素|势力表|装备表|物品表|任务表|主角信息|重要人物|世界地图点|全局数据/i.test(n)) return true;
  if (/^大纲$|^总结$|^选项$|^表格$/i.test(n)) return true;
  return false;
}

/** 宽松匹配时排除：纯数字、非物品词、无中文则不当作物名 */
function isLikelyItemName(name: string): boolean {
  const n = name.trim();
  if (n.length < 2 || n.length > 30) return false;
  if (/^\d+$|^第\d+[楼条个]?$/i.test(n)) return false;
  if (!/[\u4e00-\u9fff]/.test(n)) return false; // 至少含一个中文，避免匹配 "HP 10" 等
  if (/^(血量|生命|体力|经验|等级|伤害)/.test(n)) return false;
  if (isBlocklistedLootName(n)) return false;
  return true;
}

function guessEquipmentSlot(name: string): string {
  for (const { pattern, slot } of EQUIPMENT_SLOT_PATTERNS) {
    if (pattern.test(name)) return slot;
  }
  return '主武器';
}

function guessEquipmentGrade(name: string): string {
  for (const { pattern, grade } of EQUIPMENT_GRADE_PATTERNS) {
    if (pattern.test(name)) return grade;
  }
  return '普通';
}

function buildEquipmentEntry(name: string, quantity: number, idPrefix: string): InventoryEquipmentEntry {
  return {
    id: `${idPrefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`,
    name,
    slot: guessEquipmentSlot(name),
    grade: guessEquipmentGrade(name),
    summary: `${name}，可在状态栏中查看并手动装备。`,
    flavor: '战后搜刮得到的装备，细节待后续剧情或系统补全。',
    maxHp: 0,
    atk: 0,
    def: 0,
    speed: 0,
    crit: 0,
    effects: [],
    quantity,
  };
}

/** 从消息中提取 <LootLog>...</LootLog> 内的正文（先取再 strip），避免把剧情/表格里的「标签: 数字」当掉落解析 */
function extractLootLogBody(text: string): string {
  const match = text.match(/<LootLog>[\s\S]*?<\/LootLog>/i);
  const inner = match ? match[0].replace(/<\/?LootLog>/gi, '').trim() : '';
  return inner ? normalizeLootText(inner) : '';
}

function parseLoot(message: string): Array<{ name: string; quantity: number; category: LootCategory }> {
  const normalizedMessage = normalizeLootText(message);
  const lootLogBody = extractLootLogBody(message); // 仅在此段内跑 SETTLEMENT / LOOSE，避免误解析剧情大纲、日期等
  const byName = new Map<string, number>();
  const forcedCategoryByName = new Map<string, LootCategory>();

  let m: RegExpExecArray | null;

  // 格式零：分类前缀「材料：变异沙蟹甲壳 x3」
  CATEGORY_PREFIX_REG.lastIndex = 0;
  while ((m = CATEGORY_PREFIX_REG.exec(normalizedMessage)) !== null) {
    const rawCategory = (m[1] || '').trim();
    const name = (m[2] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    const quantity = Math.max(1, parseInt(m[3], 10) || 1);
    if (name.length < 2 || isBlocklistedLootName(name)) continue;

    const category: LootCategory =
      rawCategory === '装备'
        ? '装备'
        : rawCategory === '材料'
          ? '材料'
          : rawCategory === '重要物品' || rawCategory === '重要道具'
            ? '重要道具'
            : '消耗品';

    byName.set(name, (byName.get(name) ?? 0) + quantity);
    forcedCategoryByName.set(name, category);
  }

  // 格式一：获得: [物品名] × 数量（仅整条消息，通常出现在叙述中）
  LOOT_REG.lastIndex = 0;
  while ((m = LOOT_REG.exec(normalizedMessage)) !== null) {
    const name = (m[1] || m[2] || m[3] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    const quantity = Math.max(1, parseInt(m[4], 10) || 1);
    if (name.length >= 2 && !isBlocklistedLootName(name)) byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  // 格式二、三：仅在 <LootLog> 段落内解析，避免「剧情大纲: 3」「2085-06-15」等误入
  const scopeForSettlement = lootLogBody.length > 0 ? lootLogBody : normalizedMessage;
  SETTLEMENT_REG.lastIndex = 0;
  while ((m = SETTLEMENT_REG.exec(scopeForSettlement)) !== null) {
    const name = m[1].trim().replace(/\s+/g, ' ').slice(0, 80);
    if (isSettlementCurrencyOrSkip(name) || isBlocklistedLootName(name)) continue;
    const quantity = Math.max(1, parseInt(m[2], 10) || 1);
    byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  LOOSE_LOOT_REG.lastIndex = 0;
  while ((m = LOOSE_LOOT_REG.exec(scopeForSettlement)) !== null) {
    const name = m[1].trim().replace(/\s+/g, ' ').slice(0, 80);
    if (!isLikelyItemName(name) || isSettlementCurrencyOrSkip(name)) continue;
    const quantity = Math.max(1, parseInt(m[2], 10) || 1);
    byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  // 格式四：<LootLog> 内「物品: 名称 x 数量, 名称 x 数量」整行
  LOOTLOG_ITEMS_LINE_REG.lastIndex = 0;
  while ((m = LOOTLOG_ITEMS_LINE_REG.exec(normalizedMessage)) !== null) {
    const listStr = (m[1] || '').trim();
    let part: RegExpExecArray | null;
    LOOTLOG_ITEM_PART_REG.lastIndex = 0;
    while ((part = LOOTLOG_ITEM_PART_REG.exec(listStr)) !== null) {
      const name = (part[1] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
      if (name.length < 2 || isSettlementCurrencyOrSkip(name) || isBlocklistedLootName(name)) continue;
      const quantity = Math.max(1, parseInt(part[2], 10) || 1);
      byName.set(name, (byName.get(name) ?? 0) + quantity);
    }
  }

  const out: Array<{ name: string; quantity: number; category: LootCategory }> = [];
  for (const [name, quantity] of byName) {
    if (isBlocklistedLootName(name)) continue;
    out.push({ name, quantity, category: forcedCategoryByName.get(name) ?? classifyItemType(name) });
  }
  return out;
}

function mergeParsedLootLists(
  ...lists: Array<Array<{ name: string; quantity: number; category: LootCategory }>>
): Array<{ name: string; quantity: number; category: LootCategory }> {
  const merged = new Map<string, { name: string; quantity: number; category: LootCategory }>();

  for (const list of lists) {
    for (const entry of list) {
      const existing = merged.get(entry.name);
      if (existing) {
        existing.quantity += entry.quantity;
        continue;
      }
      merged.set(entry.name, { ...entry });
    }
  }

  return [...merged.values()];
}

/** 将解析出的战利品合并进数组：同名则累加 quantity，否则追加 */
function mergeLootInto(
  arr: Array<InventorySupplyEntry>,
  name: string,
  quantity: number,
  category: string,
  idPrefix: string,
) {
  const existing = arr.find((e) => (e.name as string)?.trim() === name);
  if (existing) {
    (existing.quantity as number) = (Number(existing.quantity) || 0) + quantity;
  } else {
    arr.push({
      name,
      category,
      quantity,
      id: `${idPrefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`,
    });
  }
}

/** 将解析出的装备合并进 inventory.equipment */
function mergeEquipmentInto(
  arr: Array<InventoryEquipmentEntry>,
  name: string,
  quantity: number,
  idPrefix: string,
) {
  const existing = arr.find((e) => e.name.trim() === name);
  if (existing) {
    existing.quantity = (Number(existing.quantity) || 0) + quantity;
    return;
  }

  arr.push(buildEquipmentEntry(name, quantity, idPrefix));
}

function tryParseAndMergeLoot(messageId: number): void {
  if (messageId == null || typeof messageId !== 'number') {
    console.warn('[战利品解析] 收到无效 messageId:', messageId);
    return;
  }
  if (HANDLED_MESSAGE_IDS.has(messageId)) return;
  const messages = getChatMessages(messageId);
  let resolvedMsg = Array.isArray(messages)
    ? messages.find((m: { message_id?: number }) => m?.message_id === messageId) ?? messages[0]
    : messages?.[0];
  let resolvedId = messageId;
  if (!resolvedMsg && typeof getChatMessages === 'function') {
    const latest = getChatMessages(-1);
    const lastMsg = Array.isArray(latest) ? latest[0] : undefined;
    if (lastMsg && lastMsg.message_id != null) {
      resolvedMsg = lastMsg;
      resolvedId = lastMsg.message_id;
      console.info('[战利品解析] 用最新楼层回退，message_id:', resolvedId);
    }
  }
  if (!resolvedMsg || resolvedMsg.role === 'user') return;

  messageId = resolvedId;
  const varOpt = { type: 'message' as const, message_id: messageId };
  const rawMessage = (resolvedMsg.message || '').trim();
  console.info('[战利品解析] 处理 message_id:', messageId, '消息长度:', rawMessage.length, '含LootLog:', /LootLog|物品\s*[：:]/.test(rawMessage));
  const scopedVariables = getVariables(varOpt) || {};
  const lootHint = _.get(scopedVariables, 'stat_data.log.lootHint', '');
  const lootHintStr = typeof lootHint === 'string' ? lootHint : String(lootHint ?? '');
  const loots = mergeParsedLootLists(
    parseLoot(rawMessage),
    lootHintStr ? parseLoot(lootHintStr) : [],
  );

  if (loots.length === 0) {
    const preview = rawMessage.slice(0, 400).replace(/\n/g, ' ');
    console.info(
      '[战利品解析] 未解析到掉落，message_id:',
      messageId,
      'lootHint长度:',
      lootHintStr.length,
      'lootHint前80字:',
      lootHintStr.slice(0, 80),
      '预览:',
      preview + (rawMessage.length > 400 ? '…' : ''),
    );
    return;
  }

  const data = Mvu.getMvuData(varOpt);
  const stat = _.get(data, 'stat_data', {}) as Record<string, unknown>;
  const inventory = _.cloneDeep(
    _.get(stat, 'inventory', {
      consumables: [],
      ammo: [],
      materials: [],
      important: [],
      equipment: [],
    }),
  ) as {
    consumables: Array<InventorySupplyEntry>;
    ammo: Array<InventorySupplyEntry>;
    materials: Array<InventorySupplyEntry>;
    important: Array<InventorySupplyEntry>;
    equipment: Array<InventoryEquipmentEntry>;
  };

  const idPrefix = 'loot';
  for (const { name, quantity, category } of loots) {
    if (category === '装备') mergeEquipmentInto(inventory.equipment, name, quantity, idPrefix);
    else if (category === '消耗品')
      mergeLootInto(inventory.consumables, name, quantity, category, idPrefix);
    else if (category === '材料') mergeLootInto(inventory.materials, name, quantity, category, idPrefix);
    else if (category === '重要道具') mergeLootInto(inventory.important, name, quantity, category, idPrefix);
  }

  _.set(data, 'stat_data.inventory', inventory);

  function persistAndDone() {
    HANDLED_MESSAGE_IDS.add(messageId);
    console.info('[战利品解析] 已追加', loots.length, '项，message_id:', messageId);
    // 同时用 replaceVariables 写回该楼层变量，确保状态栏轮询 getVariables 能读到
    try {
      const vars = getVariables(varOpt) || {};
      _.set(vars, 'stat_data.inventory', inventory);
      replaceVariables(vars, varOpt);
    } catch (e) {
      console.warn('[战利品解析] replaceVariables 回写失败', messageId, e);
    }
  }

  Mvu.replaceMvuData(data as Mvu.MvuData, varOpt).then(
    () => persistAndDone(),
    (err) => {
      console.warn('[战利品解析] replaceMvuData 失败，尝试仅用 replaceVariables', messageId, err);
      persistAndDone();
    },
  );
}

$(() => {
  (async () => {
    await waitGlobalInitialized('Mvu');

    const runAfterDelay = (messageId: number) => {
      setTimeout(() => tryParseAndMergeLoot(messageId), 1200);
    };

    eventOn(tavern_events.GENERATION_ENDED, runAfterDelay);
    eventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, (messageId: number) => runAfterDelay(messageId));
  })();
});
